# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from datetime import datetime, timedelta
import jwt

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# Initialize Web3
w3 = Web3()

# In-memory storage for nonces (use Redis/database in production)
nonces = {}
authenticated_sessions = {}

# Token expiration time (in seconds)
TOKEN_EXPIRATION = 3600  # 1 hour
NONCE_EXPIRATION = 300  # 5 minutes


def generate_nonce():
    """Generate a random nonce for signature verification"""
    return secrets.token_hex(16)


def cleanup_expired_nonces():
    """Remove expired nonces"""
    current_time = time.time()
    expired = [addr for addr, data in nonces.items() 
               if current_time - data['timestamp'] > NONCE_EXPIRATION]
    for addr in expired:
        del nonces[addr]


def verify_signature(message, signature, expected_address):
    """
    Verify that the signature matches the expected address
    
    Args:
        message: The original message that was signed
        signature: The signature string
        expected_address: The Ethereum address that should have signed the message
    
    Returns:
        bool: True if signature is valid, False otherwise
    """
    try:
        # Encode the message
        message_hash = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(message_hash, signature=signature)
        
        # Compare addresses (case-insensitive)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False


def generate_jwt_token(address):
    """Generate JWT token for authenticated user"""
    payload = {
        'address': address.lower(),
        'exp': datetime.utcnow() + timedelta(seconds=TOKEN_EXPIRATION),
        'iat': datetime.utcnow()
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')


def verify_jwt_token(token):
    """Verify JWT token and return address"""
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload['address']
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    """
    Generate and return a nonce for a given Ethereum address
    Request body: {"address": "0x..."}
    """
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    # Validate Ethereum address format
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address to checksum format
    address = Web3.to_checksum_address(address)
    
    # Clean up expired nonces
    cleanup_expired_nonces()
    
    # Generate new nonce
    nonce = generate_nonce()
    nonces[address.lower()] = {
        'nonce': nonce,
        'timestamp': time.time()
    }
    
    return jsonify({
        'nonce': nonce,
        'message': f'Sign this message to authenticate with our service.\n\nNonce: {nonce}'
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature_endpoint():
    """
    Verify signature and authenticate user
    Request body: {
        "address": "0x...",
        "signature": "0x...",
        "message": "Sign this message..."
    }
    """
    data = request.get_json()
    
    if not data or 'address' not in data or 'signature' not in data or 'message' not in data:
        return jsonify({'error': 'Address, signature, and message are required'}), 400
    
    address = data['address']
    signature = data['signature']
    message = data['message']
    
    # Validate Ethereum address
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    address_lower = address.lower()
    
    # Check if nonce exists for this address
    if address_lower not in nonces:
        return jsonify({'error': 'No nonce found for this address. Request a nonce first.'}), 400
    
    nonce_data = nonces[address_lower]
    
    # Check if nonce has expired
    if time.time() - nonce_data['timestamp'] > NONCE_EXPIRATION:
        del nonces[address_lower]
        return jsonify({'error': 'Nonce has expired. Request a new nonce.'}), 400
    
    # Verify that the message contains the correct nonce
    if nonce_data['nonce'] not in message:
        return jsonify({'error': 'Invalid message or nonce mismatch'}), 400
    
    # Verify the signature
    if not verify_signature(message, signature, address):
        return jsonify({'error': 'Invalid signature'}), 401
    
    # Remove used nonce
    del nonces[address_lower]
    
    # Generate JWT token
    token = generate_jwt_token(address)
    
    # Store authenticated session
    authenticated_sessions[address_lower] = {
        'token': token,
        'timestamp': time.time()
    }
    
    return jsonify({
        'success': True,
        'token': token,
        'address': address,
        'expiresIn': TOKEN_EXPIRATION
    }), 200


@app.route('/api/auth/validate', methods=['POST'])
def validate_token():
    """
    Validate JWT token
    Request body: {"token": "..."}
    """
    data = request.get_json()
    
    if not data or 'token' not in data:
        return jsonify({'error': 'Token is required'}), 400
    
    token = data['token']
    address = verify_jwt_token(token)
    
    if not address:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'valid': True,
        'address': address
    }), 200


@app.route('/api/auth/logout', methods=['POST'])
def logout():
    """
    Logout user and invalidate token
    Request body: {"token": "..."}
    """
    data = request.get_json()
    
    if not data or 'token' not in data:
        return jsonify({'error': 'Token is required'}), 400
    
    token = data['token']
    address = verify_jwt_token(token)
    
    if address and address in authenticated_sessions:
        del authenticated_sessions[address]
    
    return jsonify({'success': True, 'message': 'Logged out successfully'}), 200


@app.route('/api/protected', methods=['GET'])
def protected_route():
    """
    Example protected route that requires authentication
    Header: Authorization: Bearer <token>
    """
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Authorization header required'}), 401
    
    token = auth_header.split(' ')[1]
    address = verify_jwt_token(token)
    
    if not address:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'message': 'Access granted to protected resource',
        'address': address,
        'data': 'This is protected data'
    }), 200


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    return jsonify({
        'status': 'healthy',
        'service': 'Web3 Authentication Service',
        'timestamp': datetime.utcnow().isoformat()
    }), 200


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)